var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"다들 정지.","JPN":"みな、止まれ。","ENG":"Halt.","TWN":"大家都停下。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이제 곧 마지막 전투가 치러질 테니 정비를 해두어라.","JPN":"もうすぐ最後の戦闘が始まる、各自整備しておくように。","ENG":"Make preparations, for the final battle is about to commence.","TWN":"最後一戰即將打響，務必做好準備。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"바로 저 탑이 우리의 태양을 앗아간 마왕의 소굴이군요.","JPN":"あの塔が私たちの太陽を奪った魔王の巣窟なんですね。","ENG":"That tower is the lair of the Demon Lord who stole our sun.","TWN":"那座塔是偷走我們太陽的魔王巢穴。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"저기에 들어가서… 살아 돌아올 수 있을까요?","JPN":"あそこに入って……生きて帰れるんでしょうか？","ENG":"Will we... make it out of there alive?","TWN":"去那裡……能活著出來嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"승리를 의심할 것 없다. 우리 곁엔 예하께서 함께 하시니까.","JPN":"勝利を疑う必要はない。私たちには猊下がおられる。","ENG":"Do not doubt our victory. Her Eminence is on our side.","TWN":"我們的勝利毋庸置疑。因為主教與我們同在。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"우리의 믿음이 굳건한 이상, 에클레시아님은 그 어떤 강적에게도 패하지 않으신다.","JPN":"私たちの信仰が堅いのであれば、エクレシア様はいかなる強敵にも負けない。","ENG":"As long as our faith is strong, Her Eminence will not submit to any formidable foe.","TWN":"只要我們的信仰堅定，艾可露西亞就不會敗給任何強敵。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"그렇겠죠.","JPN":"そうですね。","ENG":"I believe so too.","TWN":"當然。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"하지만 이곳에 오는 동안 벌써 열 명이 넘는 전사들이 마물들에게 죽었습니다.","JPN":"しかしここに来るまでに、すでに10人以上の戦士たちが魔物に殺されました。","ENG":"However, ten of our men have already fallen on our way here.","TWN":"但這一路已經有十幾名戰士被惡魔殺死了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"다음은 제가 될지도 모르죠.","JPN":"次は私が殺されるのかもしれません。","ENG":"It will be no surprise if I am next.","TWN":"也許我就是下一個。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"전 그저, 마왕의 칼날이 노리는 게 제 목이 될까 두렵습니다.","JPN":"私はただ、魔王の剣が自分の首を狙ってくるのではないかと怖いんです。","ENG":"I just... fear that it will be my head at the end of the Demon Lord's blade.","TWN":"我只是害怕魔王的利刃會瞄準我的脖子。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"그런 불경한 말은 삼가라!","JPN":"そんな不敬な言葉は慎め！","ENG":"Such blasphemy!","TWN":"不要說這種不敬之言！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"에클레시아님! 저, 저는 더 이상 싸우고 싶지 않습니다!","JPN":"エクレシア様！　わ、私はこれ以上は戦いたくありません！","ENG":"Your Eminence! I... I do not wish to fight anymore!","TWN":"艾可露西亞！我、我不想再打了！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"예하께서 마왕을 꺾고 태양을 되찾는다 한들, 제 죽음은 영원한 어둠일 뿐이잖습니까!","JPN":"猊下が魔王に打ち勝ち、太陽を取り戻したとしても、私が死ねば永遠の闇が訪れるだけないじゃないですか！","ENG":"Though you may defeat the Demon Lord and retrieve our sun, I will be in eternal darkness if I die!","TWN":"即使您打敗魔王奪回了太陽，我卻只會在永遠的黑暗中迎來死亡！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"네놈! 우리의 성무를 모독하는 것이냐!","JPN":"貴様！　私たちの聖務を冒涜するつもりか！","ENG":"You! How dare you taint our sacred duty?!","TWN":"你！你竟敢褻瀆我們的聖務！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"열 사람 모두 추악하고 끔찍한 몰골로 죽었습니다!","JPN":"10人全員が、ひどく残酷な姿で死んでいきました！","ENG":"Ten of our men have already died gruesome deaths!","TWN":"十個人都死得很慘！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"정말 저희들의 그 참혹한 죽음 너머에 빛의 낙원이 있긴 한 건가요?!","JPN":"本当に、私たちのあんな残酷な死の向こうに光の楽園が存在するのですか！？","ENG":"Is there truly a paradise of light beyond a horrific death like that?!","TWN":"在我們那慘烈的死亡彼處，是否真的有一個光明的樂園？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"아무래도 역병의 기운에 너무 오랫동안 사로잡힌 것 같군.","JPN":"どうやら長い間疫病に晒されてしまったようだな。","ENG":"It seems that you have been exposed to the plague for too long.","TWN":"看來你已經被瘟疫侵蝕太久了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};